/******/ (() => { // webpackBootstrap
/*!********************************************!*\
  !*** ./src/scripts/sections/contact-us.js ***!
  \********************************************/
document.addEventListener("DOMContentLoaded", () => {
  const form = document.getElementById("contact-form");
  if (!form) return;

  const submitButton = form.querySelector(".contact-us__submit");
  const formMessage = document.getElementById("form-message");

  // Validation functions
  const validators = {
    first_name: (value) => {
      if (!value.trim()) return "First name is required";
      if (value.trim().length < 2) return "First name must be at least 2 characters";
      return "";
    },
    last_name: (value) => {
      if (!value.trim()) return "Last name is required";
      if (value.trim().length < 2) return "Last name must be at least 2 characters";
      return "";
    },
    phone: (value) => {
      const phoneRegex = /^[\d\s\-\+\(\)]+$/;
      if (!value.trim()) return "Phone number is required";
      if (value.trim().length < 7) return "Please enter a valid phone number";
      if (!phoneRegex.test(value)) return "Phone number can only contain numbers, spaces, and symbols";
      return "";
    },
  };

  // Validate individual fields
  const validateField = (fieldName, value) => {
    const validator = validators[fieldName];
    const errorElement = document.getElementById(`${fieldName}-error`);
    if (!errorElement) return true;

    const error = validator(value);
    if (error) {
      errorElement.textContent = error;
      return false;
    } else {
      errorElement.textContent = "";
      return true;
    }
  };

  // Clear error on field change
  form.querySelectorAll(".contact-us__input").forEach((input) => {
    input.addEventListener("input", () => {
      validateField(input.name, input.value);
    });

    input.addEventListener("blur", () => {
      validateField(input.name, input.value);
    });
  });

  // Form submission
  form.addEventListener("submit", async (e) => {
    e.preventDefault();

    // Validate all fields
    let isValid = true;
    form.querySelectorAll(".contact-us__input").forEach((input) => {
      if (!validateField(input.name, input.value)) {
        isValid = false;
      }
    });

    if (!isValid) {
      showMessage("Please fix the errors above", "error");
      return;
    }

    // Prepare form data
    const formData = new FormData(form);
    const data = {
      name: formData.get("first_name"),
      surname: formData.get("last_name"),
      phone: formData.get("phone").replace(/\D/g, ""), // Store only digits
    };

    // Disable submit button
    submitButton.disabled = true;
    submitButton.textContent = "Sending...";

    try {
      // Send to API (same endpoint as customer modal)
      const apiEndpoint = "https://form-production-51a4.up.railway.app/api/save-customer-data";
      const response = await fetch(apiEndpoint, {
        method: "POST",
        headers: {
          "Content-Type": "application/json",
        },
        body: JSON.stringify(data),
      });

      if (response.ok || response.status === 200) {
        showMessage("Thank you! We'll get back to you soon.", "success");
        form.reset();
        form.querySelectorAll(".contact-us__error").forEach((el) => {
          el.textContent = "";
        });
      } else {
        showMessage("There was an error sending your message. Please try again.", "error");
      }
    } catch (error) {
      console.error("Form submission error:", error);
      showMessage("There was an error sending your message. Please try again.", "error");
    } finally {
      submitButton.disabled = false;
      submitButton.textContent = "Send Message";
    }
  });

  function showMessage(message, type) {
    formMessage.textContent = message;
    formMessage.className = `contact-us__message ${type}`;

    if (type === "success") {
      setTimeout(() => {
        formMessage.className = "contact-us__message";
        formMessage.textContent = "";
      }, 5000);
    }
  }
});

/******/ })()
;